@* A single task card displaying title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="MoveLeftClicked">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-outline-secondary" @onclick="MoveRightClicked">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task MoveLeftClicked() => await OnMoveLeft.InvokeAsync();
    private async System.Threading.Tasks.Task MoveRightClicked() => await OnMoveRight.InvokeAsync();
}

@* Inline form to add a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" class="form-control form-control-sm mb-1" placeholder="Title" @bind="title" />
        <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee" @bind="assignee" />
        <select class="form-select form-select-sm mb-1" @bind="priority">
            <option value="">Select Priority</option>
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" class="form-control form-control-sm mb-1" @bind="dueDate" />
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">Save</button>
            <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@saving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger mt-1 small">@errorMessage</div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public string DefaultStatus { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskAdded { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = string.Empty;
    private DateTime dueDate = DateTime.Today;
    private bool saving;
    private string? errorMessage;

    [Inject]
    private ITaskService TaskService { get; set; } = default!;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        errorMessage = null;
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
        {
            errorMessage = "Title, assignee, and priority are required.";
            return;
        }

        saving = true;
        try
        {
            var newTask = await TaskService.CreateTaskAsync(title.Trim(), assignee.Trim(), priority, dueDate);
            await OnTaskAdded.InvokeAsync(newTask);
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = string.Empty;
        dueDate = DateTime.Today;
        errorMessage = null;
    }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying filtered task cards and an add-task form *@

<div class="board-column">
    <div class="column-header">
        <h5>@Status <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="@(StatusIndex > 0)"
                      ShowMoveRight="@(StatusIndex < 2)"
                      OnMoveLeft="@(() => MoveTask(task, -1))"
                      OnMoveRight="@(() => MoveTask(task, 1))" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm DefaultStatus="@Status" OnTaskAdded="HandleTaskAdded" />
    </div>
</div>

@code {
    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskAdded { get; set; }

    private int StatusIndex => Array.IndexOf(Statuses, Status);

    private async Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = StatusIndex + direction;
        if (newIndex < 0 || newIndex >= Statuses.Length) return;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[newIndex]));
    }

    private async Task HandleTaskAdded(TaskItem task)
    {
        await OnTaskAdded.InvokeAsync(task);
    }
}

@page "/board"
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3>Kanban Board</h3>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @foreach (var status in Statuses)
        {
            <BoardColumn Status="@status"
                         Tasks="@GetFilteredTasks(status)"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskAdded="HandleTaskAdded" />
        }
    </div>
}

@code {
    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    [Inject]
    private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskAdded(TaskItem task)
    {
        allTasks.Add(task);
    }
}

