@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3>Kanban Board</h3>

@if (loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @foreach (var status in Statuses)
        {
            <BoardColumn Status="@status"
                         Tasks="@GetFilteredTasks(status)"
                         OnTaskMoved="HandleTaskMoved"
                         OnTaskAdded="HandleTaskAdded" />
        }
    </div>
}

@code {
    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    [Inject]
    private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void HandleTaskAdded(TaskItem task)
    {
        allTasks.Add(task);
    }
}
"}

