@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}

@* A single Kanban column displaying filtered task cards and an add-task form *@

<div class="board-column">
    <div class="column-header">
        <h5>@Status <span class="badge bg-secondary">@Tasks.Count</span></h5>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="@(StatusIndex > 0)"
                      ShowMoveRight="@(StatusIndex < 2)"
                      OnMoveLeft="@(() => MoveTask(task, -1))"
                      OnMoveRight="@(() => MoveTask(task, 1))" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm DefaultStatus="@Status" OnTaskAdded="HandleTaskAdded" />
    </div>
</div>

@code {
    private static readonly string[] Statuses = { "To Do", "In Progress", "Done" };

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskAdded { get; set; }

    private int StatusIndex => Array.IndexOf(Statuses, Status);

    private async Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = StatusIndex + direction;
        if (newIndex < 0 || newIndex >= Statuses.Length) return;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[newIndex]));
    }

    private async Task HandleTaskAdded(TaskItem task)
    {
        await OnTaskAdded.InvokeAsync(task);
    }
}

